%[text] ## Evaluation script for a trained DQN agent
%[text] #### This script loads a previously trained RL agent and evaluates it in the environment. It shows the agent's performance in several test episodes.
clc;
clear all;
close all;
%[text] ### Environment Configuration and Data Loading
fprintf('Loading parameters and defining the environment...\n'); %[output:4496429c]
%including all parent folders up to the file 'code', this makes visible all
%files within this code
addingPathParentFolderByName('code'); %[output:880c8bf0]
% Load the same base parameters as in training
Parameters; % Script containing necessary variables %[output:081510c0] %[output:0964ecc8] %[output:8bee1410] %[output:20e31ac6] %[output:06af817a] %[output:8e187d2d] %[output:2e0abef8] %[output:8c4133c9] %[output:260a2a59] %[output:06079503]

% Load trained agent
try %[output:group:137983d4]
    % path_enhanced = fullfile('..', 'Dataset', 'dqn_agent_random_Reward_C.mat');
    path_enhanced = fullfile('..', 'Dataset', 'dqn_agent_navigation.mat');
    load(path_enhanced, 'agent','criticNet');
    fprintf('Trained agent successfully loaded.\n\n'); %[output:051f79fe]
catch
    error('The agent file "dqn_agent_random_Reward_B.mat" could not be found. Make sure it is in the same folder.');
end %[output:group:137983d4]

S = load(path_enhanced, 'trainingStats');
trainingStats = S.trainingStats;

% Pull the relevant series, defending against missing fields
epIdx       = trainingStats.EpisodeIndex(:);
epReward    = trainingStats.EpisodeReward(:);
epAvgReward = trainingStats.AverageReward(:);
epSteps     = trainingStats.EpisodeSteps(:);

if isfield(trainingStats,'TotalAgentSteps') && ~isempty(trainingStats.TotalAgentSteps)
    totalAgentSteps = trainingStats.TotalAgentSteps(:);
else
    % Fallback: cumulative episode lengths
    totalAgentSteps = cumsum(epSteps);
end

if isfield(trainingStats,'EpisodeQ0') && ~isempty(trainingStats.EpisodeQ0)
    epQ0 = trainingStats.EpisodeQ0(:);
    haveQ0 = true;
else
    epQ0 = nan(size(epIdx));
    haveQ0 = false;
end

% %% Figure 1 — training quality vs episode
% figure('Name','Training quality (per episode)','Position',[100 100 1100 700]);
% 
% plot(epIdx, epReward,    'Color',[0.6 0.6 0.6], 'LineWidth',0.8); hold on;
% plot(epIdx, epAvgReward, 'b-',  'LineWidth',2);
% xlabel('Episode','Interpreter','latex');
% ylabel('Reward','Interpreter','latex');
% title('Episode reward','Interpreter','latex');
% legend({'Per-episode','Moving average'},'Location','best','Interpreter','latex');
% grid on; set(gca,'FontSize',font);


%% Figure 1 — Enhanced Training Quality vs Episode
fig = figure('Name','Training quality (per episode)','Position',[100 100 1000 600]); %[output:785d7ca4]

% --- Styling Configurations ---
% Modern professional color palette (Deep Blue and Muted Cyan/Gray)
mainColor = [0.00, 0.45, 0.74];       % Deep corporate blue for the average line
shadeColor = [0.30, 0.75, 0.93];      % Light sky blue for the deviation band
rawColor = [0.70, 0.70, 0.70];        % Soft gray for the raw background dots
alphaValue = 0.3;                     % Transparency for the shaded area

% --- Calculate Deviation Band ---
% Calculate the standard deviation using a moving window (e.g., 20 episodes)
windowSize = 20; 
movingStd = movstd(epReward, windowSize);

% Define upper and lower bounds for the shaded area
upperBound = epAvgReward + movingStd;
lowerBound = epAvgReward - movingStd;

% Clean up bounds to ensure they align cleanly as columns for the fill function
xPoints = [epIdx; flipud(epIdx)];
yPoints = [upperBound; flipud(lowerBound)];

% --- Plotting ---
% Plot raw data as subtle background dots so it doesn't clutter the view
hRaw = plot(epIdx, epReward, '.', 'Color', rawColor, 'MarkerSize', 8);  %[output:785d7ca4]
hold on; %[output:785d7ca4]
% Plot the shaded deviation area
hShade = fill(xPoints, yPoints, shadeColor, ... %[output:785d7ca4]
    'EdgeColor', 'none', 'FaceAlpha', alphaValue); %[output:785d7ca4]
% Plot the crisp moving average line on top
hAvg = plot(epIdx, epAvgReward, 'Color', mainColor, 'LineWidth', 2.5); %[output:785d7ca4]
% --- Aesthetics & Formatting ---
grid on; %[output:785d7ca4]
set(gca, 'GridLineStyle', ':', 'GridAlpha', 0.6, 'Layer', 'top'); %[output:785d7ca4]
set(gca, 'Box', 'off', 'TickDir', 'out', 'LineWidth', 1.2); %[output:785d7ca4]
set(gca, 'FontName', 'Helvetica', 'FontSize', 12); % Fallback if 'font' variable isn't defined %[output:785d7ca4]
xlabel('Episode', 'Interpreter', 'latex', 'FontSize', 14); %[output:785d7ca4]
ylabel('Reward', 'Interpreter', 'latex', 'FontSize', 14); %[output:785d7ca4]
title('\textbf{DQN Agent Training Progress}', 'Interpreter', 'latex', 'FontSize', 16); %[output:785d7ca4]
legend([hRaw, hAvg, hShade], {'Raw Episode Reward', 'Moving Average ($\mu$)', 'Deviation ($\mu \pm \sigma$)'}, ... %[output:group:6b39f6bb] %[output:785d7ca4]
    'Location', 'best', 'Interpreter', 'latex', 'FontSize', 12); %[output:group:6b39f6bb] %[output:785d7ca4]


%% Numerical summary
nEp = numel(epReward);
[bestR, bestEp] = max(epReward);
fprintf('\n=== Training summary ===\n'); %[output:7f0b4fbc]
fprintf('Episodes completed   : %d\n', nEp); %[output:6b2dde1e]
fprintf('Total agent steps    : %d\n', totalAgentSteps(end)); %[output:0c5000dd]
fprintf('Final episode reward : %.3f\n', epReward(end)); %[output:35818ba6]
fprintf('Final avg reward     : %.3f\n', epAvgReward(end)); %[output:8449adea]
fprintf('Best episode reward  : %.3f (episode %d)\n', bestR, bestEp); %[output:0f1075fa]
fprintf('Mean steps/episode   : %.1f\n', mean(epSteps)); %[output:2eab63e6]
fprintf('========================\n\n'); %[output:1b957da4]

% After training, extract the critic (Q-network) from the agent
critic = getCritic(agent);

%% Q-function bar plot for a specific DOA
psi_x_test = 2*pi * 0.6;
psi_y_test = 2*pi * 0.3;

a_psi_x   = exp(1i * psi_x_test * ((1:EnvPars.N_x)-1))';
a_psi_y   = exp(1i * psi_y_test * ((1:EnvPars.N_y)-1))';
a_psi_x_y = kron(a_psi_y, a_psi_x);

% Query Q-network once per (t_x, t_y) position — must include position in obs
Q_map_pos = zeros(EnvPars.T_x, EnvPars.T_y);   % Q-value at best action per position

for t_psi = 1:EnvPars.T
    tx  = EnvPars.t_x(t_psi);
    ty  = EnvPars.t_y(t_psi);
    v0  = EnvPars.U_func(1:EnvPars.N, t_psi);
    r   = sqrt(db2pow(EnvPars.SNR_dB)) * EnvPars.G * diag(v0') * a_psi_x_y;

    % ← observation now includes position — matches training spec
    obs   = [abs(r).^2; tx; ty];              % (N+2) × 1
    Q_all = getValue(critic, {obs});           % 1 × n_actions (9 values)
    Q_map_pos(tx, ty) = max(Q_all);           % best Q at this position
end
%%

% Bar plot — Q-value across all 144 (t_x,t_y) positions
figure; %[output:2493a714]
bar(1:EnvPars.T, Q_map_pos(:), 'FaceColor', [0.2 0.5 0.8]); %[output:2493a714]
xlabel('Action $t_\psi$', 'Interpreter', 'latex'); %[output:2493a714]
ylabel('$\max_a Q(s, a)$', 'Interpreter', 'latex'); %[output:2493a714]
title(sprintf('Q-function over positions | $\\psi_x$=%.2f, $\\psi_y$=%.2f', ... %[output:2493a714]
              psi_x_test, psi_y_test), 'Interpreter', 'latex'); %[output:2493a714]
grid on; %[output:2493a714]

%% Q heatmap over (psi_x, t_curr_position)
N_test    = 20;
psi_x_vec = linspace(0, 2*pi, N_test);

% Fix starting position at centre of grid for the sweep
tx_fixed  = round(EnvPars.T_x / 2);
ty_fixed  = round(EnvPars.T_y / 2);

Q_map = zeros(N_test, EnvPars.n_actions);   % n_actions=9, not T

for i = 1:N_test
    a_x   = exp(1i * psi_x_vec(i) * ((1:EnvPars.N_x)-1))';
    a_y   = exp(1i * pi            * ((1:EnvPars.N_y)-1))';
    t_psi = (ty_fixed - 1) * EnvPars.T_x + tx_fixed;
    v0    = EnvPars.U_func(1:EnvPars.N, t_psi);
    r     = sqrt(db2pow(EnvPars.SNR_dB)) * EnvPars.G * diag(v0') * kron(a_y, a_x);

    % ← position appended
    obs        = [abs(r).^2; tx_fixed; ty_fixed];   % (N+2) × 1
    Q_map(i,:) = getValue(critic, {obs});            % 1 × 9
end

figure; %[output:5b6d20a6]
imagesc(1:EnvPars.n_actions, psi_x_vec, Q_map); %[output:5b6d20a6]
colorbar; %[output:5b6d20a6]
xlabel('Navigation action (1-9)', 'Interpreter', 'latex'); %[output:5b6d20a6]
ylabel('$\psi_x$',               'Interpreter', 'latex'); %[output:5b6d20a6]
title('$Q(s(psi_x), a)$  does argmax track the peak direction?', ... %[output:group:76caef3d] %[output:5b6d20a6]
      'Interpreter', 'latex'); %[output:group:76caef3d] %[output:5b6d20a6]
%[text] #### Theoretical evaluation of the Q function
%% Theoretical Q★ via Dynamic Programming (Value Iteration)
% State space:  (pos_idx, t_x, t_y) — calibration position + grid location
% Action space: 9 relative moves from EnvPars.delta_moves
% Reward:       peak_map(pos, t_x, t_y) / global_max(pos)

Calibration %[output:568063d5]

fprintf('=== Value Iteration for Q★ ===\n'); %[output:0a91c1d0]

%% Parameters
gamma     = 0.5;
tol_conv  = 1e-6;
max_iter  = 1000;
n_a       = EnvPars.n_actions;   % 9
T_x       = EnvPars.T_x;         % 12
T_y       = EnvPars.T_y;         % 12
N_cal     = EnvPars.N_cal;

%% Precompute normalised reward for every (pos, t_x, t_y)
% R(pos, tx, ty) = peak_map(pos, tx, ty) / global_max(pos)
R_map = zeros(N_cal, T_x, T_y);
for pos = 1:N_cal
    % R_map(pos,:,:) = (squeeze(peak_map(pos,:,:)) / EnvPars.global_max_cal(pos)).^2;   % normalised ∈ (0,1]
    threshold = 0.8;   % only positions with >80% of peak get positive reward
    slice     = squeeze(peak_map(pos,:,:)) / EnvPars.global_max_cal(pos);
    R_map(pos,:,:) = max(0, (slice - threshold) / (1 - threshold));
end

%% Value function V★(pos, t_x, t_y) — initialise to zero
V     = zeros(N_cal, T_x, T_y);
V_new = zeros(N_cal, T_x, T_y);

%% Value Iteration
for iter = 1:max_iter %[output:group:545fed66]
    V_old = V;

    for pos = 1:N_cal
        for tx = 1:T_x
            for ty = 1:T_y

                % Immediate reward at current position
                r_now = R_map(pos, tx, ty);

                % Evaluate all 9 actions — find max future value
                Q_vals = zeros(n_a, 1);
                for a = 1:n_a
                    % Next position — wrap around grid edges
                    tx_next = mod(tx - 1 + EnvPars.delta_moves(a,1), T_x) + 1;
                    ty_next = mod(ty - 1 + EnvPars.delta_moves(a,2), T_y) + 1;

                    % Bellman equation
                    Q_vals(a) = r_now + gamma * V(pos, tx_next, ty_next);
                end

                V_new(pos, tx, ty) = max(Q_vals);
            end
        end
    end

    V = V_new;

    % Check convergence
    delta_V = max(abs(V(:) - V_old(:)));
    if mod(iter, 50) == 0
        fprintf('  Iteration %d | max ΔV = %.2e\n', iter, delta_V);
    end
    if delta_V < tol_conv
        fprintf('Converged at iteration %d | max ΔV = %.2e\n', iter, delta_V); %[output:5279075e]
        break;
    end
end %[output:group:545fed66]

%% Extract Q★ and optimal policy π★ from converged V
% Q★(pos, tx, ty, a) = R(pos,tx,ty) + γ * V★(pos, tx_next, ty_next)
Q_star = zeros(N_cal, T_x, T_y, n_a);
policy = zeros(N_cal, T_x, T_y);   % optimal action index (1–9)

for pos = 1:N_cal
    for tx = 1:T_x
        for ty = 1:T_y
            r_now  = R_map(pos, tx, ty);
            Q_vals = zeros(n_a, 1);

            for a = 1:n_a
                tx_next  = mod(tx - 1 + EnvPars.delta_moves(a,1), T_x) + 1;
                ty_next  = mod(ty - 1 + EnvPars.delta_moves(a,2), T_y) + 1;
                Q_vals(a) = r_now + gamma * V(pos, tx_next, ty_next);
            end

            [~, policy(pos, tx, ty)] = max(Q_vals);
            Q_star(pos, tx, ty, :)   = Q_vals;
        end
    end
end

fprintf('Q★ and π★ computed for all %d positions.\n\n', N_cal); %[output:27163e2d]

%% ── PLOTS ────────────────────────────────────────────────────────────────

%% Plot 1 — V★ landscape for one calibration position
pos_probe = round(N_cal * 0.6);   % pick a representative position
figure; %[output:2561d9e8]
imagesc(1:T_x, 1:T_y, squeeze(V(pos_probe,:,:))'); %[output:2561d9e8]
colorbar; axis xy; %[output:2561d9e8]
hold on; %[output:2561d9e8]
plot(EnvPars.best_tx_cal(pos_probe), EnvPars.best_ty_cal(pos_probe), ... %[output:2561d9e8]
     'rx', 'MarkerSize', 16, 'LineWidth', 2.5); %[output:2561d9e8]
xlabel('$t_x$', 'Interpreter','latex'); %[output:2561d9e8]
ylabel('$t_y$', 'Interpreter','latex'); %[output:2561d9e8]
title(sprintf('$V^\\star(t_x,t_y)$ at calibration pos %d | $\\psi_x$=%.2f rad', ... %[output:2561d9e8]
              pos_probe, EnvPars.psi_x_cal(pos_probe)), 'Interpreter','latex'); %[output:2561d9e8]
set(gca,'FontSize',12); %[output:2561d9e8]

%% Plot 2 — Optimal policy arrow map for same position
figure; hold on; %[output:969bcede]
imagesc(1:T_x, 1:T_y, squeeze(R_map(pos_probe,:,:))'); %[output:969bcede]
alpha(0.5); axis xy; colorbar; %[output:969bcede]

for tx = 1:T_x
    for ty = 1:T_y
        a  = policy(pos_probe, tx, ty);
        dx = EnvPars.delta_moves(a, 1);
        dy = EnvPars.delta_moves(a, 2);
        if dx == 0 && dy == 0
            plot(tx, ty, 'ko', 'MarkerSize', 5);   % stay action
        else
            quiver(tx, ty, dx*0.35, dy*0.35, 0, ... %[output:969bcede]
                   'Color', [0 0 0.8], 'LineWidth', 1.2, 'MaxHeadSize', 1.5); %[output:969bcede]
        end
    end
end
plot(EnvPars.best_tx_cal(pos_probe), EnvPars.best_ty_cal(pos_probe), ... %[output:969bcede]
     'rx', 'MarkerSize', 16, 'LineWidth', 2.5); %[output:969bcede]
xlim([0.5, T_x+0.5]); ylim([0.5, T_y+0.5]); %[output:969bcede]
xlabel('$t_x$', 'Interpreter','latex'); %[output:969bcede]
ylabel('$t_y$', 'Interpreter','latex'); %[output:969bcede]
title(sprintf('Optimal policy $\\pi^\\star$ at pos %d | $\\psi_x$=%.2f rad', ... %[output:969bcede]
              pos_probe, EnvPars.psi_x_cal(pos_probe)), 'Interpreter','latex'); %[output:969bcede]
set(gca,'FontSize',12); %[output:969bcede]


%% Plot 3 — Q★ over the 9 actions at the starting position
% Shows which action has the highest Q-value before any move
tx_start = randi(T_x);
ty_start = randi(T_y);
Q_at_start = squeeze(Q_star(pos_probe, tx_start, ty_start, :));

action_labels = {'-1,-1'; '-1,0'; '-1,+1'; '0,-1'; '0,0'; '0,+1'; '+1,-1'; '+1,0'; '+1,+1'};
figure; %[output:45dfc68f]
bar(1:n_a, Q_at_start, 'FaceColor', [0.2 0.5 0.8]); %[output:45dfc68f]
xticks(1:n_a); %[output:45dfc68f]
xticklabels(action_labels); %[output:45dfc68f]
xlabel('Navigation action $(\Delta t_x, \Delta t_y)$', 'Interpreter','latex'); %[output:45dfc68f]
ylabel('$Q^\star(s, a)$',                               'Interpreter','latex'); %[output:45dfc68f]
title(sprintf('$Q^\\star$ at start $(t_x=%d, t_y=%d)$ | pos %d', ... %[output:45dfc68f]
              tx_start, ty_start, pos_probe), 'Interpreter','latex'); %[output:45dfc68f]
[~, best_a] = max(Q_at_start);
xline(best_a, 'r--', 'LineWidth', 2, 'Label', '$\pi^\star$', ... %[output:45dfc68f]
      'Interpreter', 'latex'); %[output:45dfc68f]
grid on; set(gca,'FontSize',12); %[output:45dfc68f]

%% Plot 4 — Simulate optimal policy from random starts, measure steps to peak
N_sim         = 100;
steps_to_peak = zeros(N_cal, N_sim);

for pos = 1:N_cal
    for sim = 1:N_sim
        tx = randi(T_x);
        ty = randi(T_y);

        for k = 1:EnvPars.MaxStepsPerEpisode
            a       = policy(pos, tx, ty);
            tx_next = mod(tx - 1 + EnvPars.delta_moves(a,1), T_x) + 1;
            ty_next = mod(ty - 1 + EnvPars.delta_moves(a,2), T_y) + 1;

            if tx_next == EnvPars.best_tx_cal(pos) && ...
               ty_next == EnvPars.best_ty_cal(pos)
                steps_to_peak(pos, sim) = k;
                break;
            end
            tx = tx_next;
            ty = ty_next;
        end
    end
end

figure; %[output:0757801c]
histogram(steps_to_peak(steps_to_peak > 0), ... %[output:0757801c]
          'BinWidth', 1, 'FaceColor', [0.2 0.5 0.8], 'Normalization','probability'); %[output:0757801c]
xlabel('Steps to reach peak',    'Interpreter','latex'); %[output:0757801c]
ylabel('Fraction of episodes',   'Interpreter','latex'); %[output:0757801c]
title('Steps needed by $\pi^\star$ from random starts', 'Interpreter','latex'); %[output:0757801c]
xline(mean(steps_to_peak(steps_to_peak>0)), 'r--', 'LineWidth', 2, ... %[output:0757801c]
      'Label', 'mean', 'Interpreter','latex'); %[output:0757801c]
grid on; set(gca,'FontSize',12); %[output:0757801c]

%% Summary
reached     = steps_to_peak(steps_to_peak > 0);
not_reached = sum(steps_to_peak(:) == 0);
fprintf('=== Optimal policy simulation (%d starts × %d positions) ===\n', N_sim, N_cal); %[output:30baf396]
fprintf('Mean steps to peak   : %.2f\n',  mean(reached)); %[output:6ab731e7]
fprintf('Max  steps to peak   : %d\n',    max(reached)); %[output:8ff5fa0c]
fprintf('Never reached peak   : %.1f%%n', 100*not_reached/(N_cal*N_sim)); %[output:1ba98a1f]
fprintf('Within MaxSteps (%d) : %.1f%%n', EnvPars.MaxStepsPerEpisode, ... %[output:group:97a0ee17] %[output:8a3ec652]
        100*mean(reached <= EnvPars.MaxStepsPerEpisode)); %[output:group:97a0ee17] %[output:8a3ec652]
fprintf('=========================================================\n'); %[output:2feb816f]
%%
%[text] ### Evaluation for a given number of steps
% Parameters
t = 0:delta_time:time_simul;     % time vector in s

EnvPars.tolerance = pi/25;
%% Initialization
Nsteps = length(t);
pos_MU_traj = zeros(3, Nsteps);

% Initial position
current_pos = pos_MU_init(:);
current_pos(1) = min(max(current_pos(1), 0), L_hall);
current_pos(2) = min(max(current_pos(2), 0), W_hall);

pos_MU_traj(:,1) = current_pos;

% Initial mobility state
state = "move";   % either "move" or "pause"

% First target waypoint
target_pos = [L_hall*rand; W_hall*rand; current_pos(3)];

% Pause handling
pause_end_time = -inf;

%% Time evolution
for k = 2:Nsteps
    
    dt = t(k) - t(k-1);
    
    % In case of non-positive time step, keep previous position
    if dt <= 0
        pos_MU_traj(:,k) = pos_MU_traj(:,k-1);
        continue;
    end
    
    if state == "move"
        
        % Vector toward target
        dvec = target_pos(1:2) - current_pos(1:2);
        dist_to_target = norm(dvec);
        travel_dist = MU_speed * dt;
        
        if dist_to_target <= travel_dist
            % Reach waypoint within this time step
            current_pos(1:2) = target_pos(1:2);
            
            % Switch to pause state
            pause_duration = pause_min + (pause_max - pause_min)*rand;
            pause_end_time = t(k) + pause_duration;
            state = "pause";
            
        else
            % Move toward waypoint
            direction = dvec / dist_to_target;
            current_pos(1:2) = current_pos(1:2) + direction * travel_dist;
        end
        
    elseif state == "pause"
        
        % Stay still during pause
        if t(k) >= pause_end_time
            % Pause finished, choose new waypoint and move again
            target_pos = [L_hall*rand; W_hall*rand; current_pos(3)];
            state = "move";
        end
        
    end
    
    % Store position
    pos_MU_traj(:,k) = current_pos;
end

% Enforce constant z-coordinate
pos_MU_traj(3,:) = pos_MU_init(3);

%[text] #### Including the channel coherence time
%[text] **Description**:In this block we include the number of transmittions along wich the channel is coherent.This is similar to assuming the user keeps the same position.
pos_MU_traj = repelem(pos_MU_traj, 1, floor(N_packets_coh*delta_time/T_coh));
%[text] #### Ploting the mobility of the user
figure; %[output:833bbbe7]
plot(pos_MU_traj(1,:), pos_MU_traj(2,:), 'b-', 'LineWidth', 1.5); hold on; %[output:833bbbe7]
plot(pos_MU_traj(1,1), pos_MU_traj(2,1), 'go', 'MarkerSize', 8, 'LineWidth', 1.5); %[output:833bbbe7]
plot(pos_MU_traj(1,end), pos_MU_traj(2,end), 'ro', 'MarkerSize', 8, 'LineWidth', 1.5); %[output:833bbbe7]
xlim([0 L_hall]); %[output:833bbbe7]
ylim([0 W_hall]); %[output:833bbbe7]
xlabel('x [m]'); %[output:833bbbe7]
ylabel('y [m]'); %[output:833bbbe7]
title('Random Waypoint Mobility with Random Pause'); %[output:833bbbe7]
grid on; %[output:833bbbe7]
axis equal; %[output:833bbbe7]
legend('Trajectory','Start','End'); %[output:833bbbe7]

% %% Animation of the mobile user trajectory
% 
% figure;
% hold on;
% grid on;
% axis equal;
% xlim([0 L_hall]);
% ylim([0 W_hall]);
% xlabel('$x$ [m]','Interpreter','latex');
% ylabel('$y$ [m]','Interpreter','latex');
% title('Mobile User Random Waypoint Trajectory');
% 
% % Draw hall boundary
